from flask import Flask, redirect, request, session, url_for
import requests
import jwt

app = Flask(__name__)
app.secret_key = 'your_secret_key'

OIDC_PROVIDER = 'https://your-oidc-provider.com'
CLIENT_ID = 'your_client_id'
REDIRECT_URI = 'http://localhost:5000/callback'
SCOPE = 'openid'
RESPONSE_TYPE = 'id_token'

@app.route('/')
def home():
    if 'id_token' in session:
        return 'Logged in as: {}'.format(jwt.decode(session['id_token'], options={"verify_signature": False})['sub'])
    return redirect(url_for('login'))

@app.route('/login')
def login():
    authorization_url = f"{OIDC_PROVIDER}/authorize?client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope={SCOPE}&response_type={RESPONSE_TYPE}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if id_token:
        session['id_token'] = id_token
    return redirect(url_for('home'))

@app.route('/logout')
def logout():
    session.pop('id_token', None)
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(ssl_context='adhoc')